import SwiftUI
import UIKit

struct ActivityView: UIViewControllerRepresentable {
    let items: [Any]
    var excludedTypes: [UIActivity.ActivityType]? = nil

    func makeUIViewController(context: Context) -> UIActivityViewController {
        let controller = UIActivityViewController(activityItems: items, applicationActivities: nil)
        controller.excludedActivityTypes = excludedTypes
        return controller
    }

    func updateUIViewController(_ uiViewController: UIActivityViewController, context: Context) {}
}

enum ShareHelper {
    static func renderViewToImage<V: View>(_ view: V, size: CGSize? = nil) -> UIImage? {
        let renderer = ImageRenderer(content: view)
        renderer.scale = UIScreen.main.scale
        if let size = size {
            renderer.proposedSize = .init(width: size.width, height: size.height)
        }
        return renderer.uiImage
    }

    static func copyToClipboard(_ text: String) {
        UIPasteboard.general.string = text
    }

    static func copyImageToClipboard(_ image: UIImage) {
        UIPasteboard.general.image = image
    }
}
